import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as l,c as e,e as p}from"./app-380ba173.js";const a={},r=p('<h2 id="感情" tabindex="-1"><a class="header-anchor" href="#感情" aria-hidden="true">#</a> 感情</h2><ul><li><p>因为有你在，所以我才敢放肆的去做正义的事情，不怕被坏人欺负，因为你会为我撑腰。</p></li><li><p>人事间的事情莫过于此，用一个瞬间来喜欢一样东西，用余生来慢慢拷问自己。</p></li><li><p>当主角多累啊，闪闪发光的，还得保证每个人都能看到，你不一定非要成为太阳，想做个星星，萤火虫，路灯都行，想发光的时候就发光，哪怕你永远都不发光，有的人还是一眼就看到你了。</p></li><li><p>到了一个陌生的地方，就要慢慢的填满自己的东西，这样才会有归属感。</p></li><li><p>在我活着的人生里，仅仅只是为了活着，梦想真是一个好东西，他让我觉得不只活着。</p></li><li><p>生命的烙印不会因为你的瞎想而发生一点点的改变。</p></li><li><p>尽量让自己开心一点，但也别把明天的路堵死。</p></li><li><p>不要困于别人的期待，徒耗自己的精力。</p></li><li><p>不要让自己有负罪感，因为负罪感会抢走灵魂。</p></li><li><p>无论如何你走的路都会被人说三到四，做也会被人说，不做也会被人说，那就在自己想做的情况下做吧。</p></li></ul><h2 id="商业" tabindex="-1"><a class="header-anchor" href="#商业" aria-hidden="true">#</a> 商业</h2><ul><li><p>趋势决定战略，战略决定业务，业务决定组织，组织决定人才。</p></li><li><p>未来的眼光看现在，产业的眼光看行业，行业的眼光看企业，资本的眼光看产品。</p></li><li><p>统一不了意识就统一目标</p></li><li><p>工人付出最大的努力防止工人辞职，雇主提供最少的工资以防止工人辞职。</p></li><li><p>逻辑是个结构和内容问题，情感是个立场问题，思维是一个角度问题。</p></li></ul>',4),t=[r];function o(c,n){return l(),e("div",null,t)}const h=i(a,[["render",o],["__file","Love brain.html.vue"]]);export{h as default};
